49	fn main() -> ExitCode {
50	    let args: Vec<String> = std::env::args().collect();
51	
52	    if args.get(1).map(|s| s.as_str()) == Some("single") {
53	        return rbtdb_run_single(&args[2..]);
54	    }
55	
56	    rbtdb_run_suite(&args[1..])
