59	fn rbtdb_read_dispatch_dir(name: &str) -> Result<PathBuf, String> {
60	    match std::env::var(name) {
61	        Ok(v) if !v.is_empty() => rbtdrx_posix_to_native(&v),
62	        _ => Err(format!(
63	            "rbtd: {} is not set — theurge must be launched via BUK tabtarget",
64	            name
65	        )),
66	    }
67	}
