281	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
282	///
283	/// Expects the invocation context to already be installed in the thread-local
284	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
285	///
286	/// Setup failure short-circuits cases but still invokes teardown. Teardown
287	/// errors are surfaced as warnings via stderr; the function never panics on
288	/// teardown failure.
289	pub fn rbtdre_run_fixture(
290	    fixture: &'static rbtdre_Fixture,
291	    colors: &rbtdre_Colors,
292	    root_temp: &Path,
293	) -> Result<rbtdre_RunResult, String> {
294	    let setup_result = match fixture.setup {
